#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int k;
    cin >> k;
    int max_len = 0, left = 0, zeros = 0;
    for(int right = 0; right < n; right++){
        if(nums[right] == 0) zeros++;
        while(zeros > k){
            if(nums[left] == 0) zeros--;
            left++;
        }
        max_len = max(max_len, right - left + 1);
    }
    cout << max_len;
}
